using System;

namespace jumptest
{
    /// <summary>
    /// One row of a many-to-many ("map") relationship checklist tab (see
    /// MetaObject.MapRelationships / MetaObject.ProcessMapRelationships in
    /// src/metamodel.cs, and the query generated by
    /// database/{pgsql,mssql}/data/template.map.generated.sql.cshtml).
    /// Populated via DBPersist.autoAssign, which writes raw reader values
    /// straight into this BaseObject's dictionary by column name -- the
    /// typed properties below just read them back with a defensive
    /// conversion, matching the id/label/mapped columns the generated query
    /// selects.
    /// </summary>
    public class MapOption : BaseObject
    {
        public long id
        {
            get
            {
                try { return Convert.ToInt64(this["id"]); }
                catch { return 0; }
            }
            set { this["id"] = value; }
        }

        public string label
        {
            get
            {
                try { return this["label"]?.ToString() ?? string.Empty; }
                catch { return string.Empty; }
            }
            set { this["label"] = value; }
        }

        public bool mapped
        {
            get
            {
                try { return Convert.ToBoolean(this["mapped"]); }
                catch { return false; }
            }
            set { this["mapped"] = value; }
        }
    }
}
